function isValidUrl(url) {
    if (typeof url !== 'string') return false;

    const pattern = /^(https?:\/\/)[^\s/$.?#].[^\s]*$/i;
    return pattern.test(url);
}

const inputUrl = $input.first().json.url;

return [
    {
        json: {
            url: inputUrl,
            isValid: isValidUrl(inputUrl) ? 'yes' : 'no'
        }
    }
];

